/**
 * AhaMomentPanel — "Why this stands out" explainer for strategy detail.
 * Converts raw metrics into plain-language confidence signals.
 */
import { tokens } from '../styles/tokens';
import GlassPanel from './ui/GlassPanel';

const T = {
  text: tokens.color.text, textSec: tokens.color.textSecondary,
  green: tokens.color.green, blue: tokens.color.blue, amber: tokens.color.amber,
  purple: tokens.color.purple, mono: tokens.font.mono,
};

export default function AhaMomentPanel({ strategy }) {
  if (!strategy) return null;

  const reasons = [];

  const wf = strategy.walk_forward_score || strategy.walk_forward?.score || 0;
  const regime = strategy.regime_stability_score || 0;
  const alpha = strategy.alpha_score || 0;
  const sharpe = strategy.sharpe || strategy.performance?.sharpe || 0;
  const pf = strategy.profit_factor || strategy.performance?.profit_factor || 0;

  if (wf >= 0.50)
    reasons.push({ icon: '✓', text: 'Passed walk-forward validation', detail: `Score: ${wf.toFixed(2)} — performs out-of-sample, not just in hindsight`, color: T.green });
  if (regime >= 0.50)
    reasons.push({ icon: '🛡', text: 'Stable across market regimes', detail: `Tested in bull, bear, sideways, and volatile conditions`, color: T.blue });
  if (alpha >= 0.60)
    reasons.push({ icon: '🏆', text: 'Ranked highly vs peers', detail: `Alpha score ${alpha.toFixed(2)} — top tier of all evaluated strategies`, color: T.amber });
  if (sharpe >= 1.0)
    reasons.push({ icon: '📈', text: 'Strong risk-adjusted returns', detail: `Sharpe ${sharpe.toFixed(2)} — good return per unit of risk taken`, color: T.green });
  if (pf >= 1.4)
    reasons.push({ icon: '💰', text: 'Favorable profit factor', detail: `PF ${pf.toFixed(2)} — gross profits meaningfully exceed gross losses`, color: T.purple });

  if (reasons.length === 0) return null;

  return (
    <GlassPanel style={{ marginBottom: 16, border: `1px solid ${T.green}22` }}>
      <div style={{
        fontSize: 11, fontWeight: 700, fontFamily: T.mono, color: T.green,
        letterSpacing: '0.05em', textTransform: 'uppercase', marginBottom: 12,
      }}>
        Why this stands out
      </div>
      <div style={{ fontSize: 11, color: T.textSec, marginBottom: 12, lineHeight: 1.5 }}>
        These metrics show how well this strategy holds up over time — not just recent performance.
      </div>
      {reasons.map(r => (
        <div key={r.text} style={{
          display: 'flex', alignItems: 'flex-start', gap: 12, padding: '8px 0',
          borderBottom: `1px solid ${T.textSec}10`,
        }}>
          <span style={{ fontSize: 14, flexShrink: 0, marginTop: 4 }}>{r.icon}</span>
          <div>
            <div style={{ fontSize: 13, fontWeight: 600, fontFamily: T.mono, color: r.color }}>{r.text}</div>
            <div style={{ fontSize: 11, color: T.textSec, marginTop: 4 }}>{r.detail}</div>
          </div>
        </div>
      ))}
    </GlassPanel>
  );
}
